-- PostgreSQL seed for Car Rentals database

CREATE TABLE IF NOT EXISTS rental_companies (
  id VARCHAR(255) PRIMARY KEY,
  name VARCHAR(255) NOT NULL,
  slug VARCHAR(255) UNIQUE NOT NULL,
  tier VARCHAR(50),
  commission_rate NUMERIC,
  hq_country VARCHAR(100),
  description TEXT
);


CREATE TABLE IF NOT EXISTS vehicle_models (
  id VARCHAR(255) PRIMARY KEY,
  brand VARCHAR(100),
  model VARCHAR(100),
  year INT,
  category VARCHAR(50),
  transmission VARCHAR(20),
  fuel_type VARCHAR(30),
  horsepower INT,
  doors INT,
  seats INT,
  price_index NUMERIC
);


CREATE TABLE IF NOT EXISTS rental_locations (
  id VARCHAR(255) PRIMARY KEY,
  name VARCHAR(255),
  type VARCHAR(30),
  city VARCHAR(100),
  country VARCHAR(100),
  country_code VARCHAR(2),
  region VARCHAR(30),
  lat NUMERIC,
  lon NUMERIC,
  currency VARCHAR(3),
  airport_code VARCHAR(3),
  cost_index NUMERIC
);

